html:
{% set s = frappe.get_single("WAFD Print Settings") %}
{% set logo = doc.company_logo or s.company_logo or "/assets/wafd_one/images/wafd-almadinah-official.png" %}
{% set signature = doc.signature_image or s.default_signature %}
{% set stamp = doc.company_stamp or s.default_stamp %}
<style>
@page {
  size: {{ s.paper_size or 'A4' }}{% if s.orientation == 'Landscape' %} landscape{% endif %};
  margin: {{ s.margin_top or 5 }}mm {{ s.margin_right or 14 }}mm {{ s.margin_bottom or 15 }}mm {{ s.margin_left or 14 }}mm;
}
html, body { margin: 0 !important; padding: 0 !important; }
.undertaking {
  direction: rtl;
  text-align: right;
  font-family: "{{ s.font_family or 'Tahoma' }}", Arial, sans-serif;
  color: {{ s.text_color or '#111111' }};
  font-size: {{ s.base_font_size or 13 }}px;
  line-height: 1.72;
  box-sizing: border-box;
  padding-bottom: 11mm;
}
.u-head {
  position: relative;
  height: 112px;
  overflow: hidden;
  margin: 0 0 2px 0;
  padding: 0;
  border: 0 !important;
}
.undertaking .wafd-logo {
  position: absolute;
  top: 0;
  right: 0;
  width: 112px !important;
  min-width: 112px !important;
  max-width: 112px !important;
  height: auto !important;
  max-height: 112px !important;
  object-fit: contain;
  display: block;
  margin: 0 !important;
  padding: 0 !important;
}
h1 {
  text-align: center;
  font-size: {{ s.title_font_size or 18 }}px;
  text-decoration: underline;
  margin: 3px 0 8px;
  color: {{ s.text_color or '#111111' }};
}
.meta { display:flex; justify-content:space-between; font-size:11px; margin-bottom:4px; }
.party { margin:7px 0; }
.party-title { font-weight:700; font-size:14px; }
.terms { margin:8px 0 0; padding-right:20px; }
.terms li { padding-right:3px; margin-bottom:2px; }
.closing { margin-top:7px; }
.sign {
  margin-top: 8px;
  width: 100%;
  border-collapse: collapse;
  page-break-inside: avoid !important;
  break-inside: avoid !important;
}
.sign td { width:50%; text-align:center; vertical-align:top; padding:0 10px; }
.sign-block { min-height: 105px; }
.sign-name { line-height:1.55; }
.image-box {
  height: 58px;
  margin-top: 4px;
  display:flex;
  align-items:center;
  justify-content:center;
}
.sign-img {
  display:block;
  width:auto !important;
  height:auto !important;
  max-width:150px !important;
  max-height:52px !important;
  object-fit:contain;
  margin:0 auto !important;
}
.stamp-img {
  display:block;
  width:auto !important;
  height:auto !important;
  max-width:145px !important;
  max-height:62px !important;
  object-fit:contain;
  margin:0 auto !important;
}
.footer {
  position: fixed !important;
  left: {{ s.margin_left or 14 }}mm;
  right: {{ s.margin_right or 14 }}mm;
  bottom: 1.5mm;
  min-height: 7mm;
  box-sizing: border-box;
  border-top: 0.35px solid {{ s.primary_color or '#AA8C27' }};
  padding-top: 1.6mm;
  margin: 0 !important;
  text-align: center;
  direction: ltr;
  color: {{ s.primary_color or '#AA8C27' }};
  font-size: 9px;
  line-height: 1.2;
  background: #fff;
  white-space: nowrap;
  overflow: hidden;
  z-index: 20;
}
.watermark-text { position:fixed; opacity:{{ s.watermark_opacity or 0.05 }}; font-size:100px; transform:rotate(-25deg); top:42%; right:20%; z-index:-1; }
.watermark-logo { position:fixed; opacity:{{ s.watermark_opacity or 0.05 }}; width:360px; max-height:360px; object-fit:contain; top:30%; right:25%; z-index:-1; }
@media screen {
  .footer { bottom: 1.5mm; }
}
@media print {
  .u-head, h1, .meta { page-break-after: avoid; break-after: avoid; }
  .footer { position: fixed !important; }
  .undertaking { overflow: visible !important; }
}
</style>
<div class="undertaking">
{% if s.show_watermark %}{% if s.watermark_logo %}<img class="watermark-logo" src="{{ frappe.utils.get_url(s.watermark_logo) }}">{% else %}<div class="watermark-text">{{ s.watermark_text or 'وفد' }}</div>{% endif %}{% endif %}
<div class="u-head"><img class="wafd-logo" src="{{ frappe.utils.get_url(logo) }}"></div>
<h1>{{ s.document_title or 'تعهد والتزام إعاشة' }}</h1>
<div class="meta">{% if s.show_reference_number %}<span><b>رقم التعهد:</b> {{ doc.name }}</span>{% endif %}<span><b>التاريخ:</b> {{ frappe.utils.formatdate(doc.undertaking_date, 'yyyy/MM/dd') }}</span></div>
<p><b>{{ s.intro_text or 'الحمد لله، والصلاة والسلام على رسول الله، وبعد:' }}</b></p><p>{{ s.agreement_text or 'فقد تم الاتفاق على هذا التعهد بين:' }}</p>
<div class="party"><div class="party-title">الطرف الأول:</div>{{ doc.company_name }}، بموجب السجل التجاري رقم ({{ doc.company_cr }})، ويمثلها السيد/ {{ doc.company_representative }}.</div>
<div class="party"><div class="party-title">الطرف الثاني:</div>{{ doc.second_party_name }}{% if doc.second_party_cr %}، سجل تجاري رقم ({{ doc.second_party_cr }}){% endif %}{% if doc.second_party_representative %}، ويمثلها السيد/ {{ doc.second_party_representative }}{% endif %}، ويشار إليها في هذا التعهد بـ(الطرف الثاني).</div>
<p><b>حيث اتفق الطرفان على الآتي:</b></p>
<ol class="terms"><li>يقوم الطرف الأول بتأمين وجبات ({{ (doc.meal_types or '').replace('\n', ' – ') }}) لعدد ({{ doc.beneficiary_count }}) مستفيد{% if doc.nationality %} من الجنسية {{ doc.nationality }}{% endif %}.</li><li>موقع التوريد: {{ doc.supply_location or doc.hotel }}.</li><li>مدة التعهد من تاريخ {{ frappe.utils.formatdate(doc.start_date, 'yyyy/MM/dd') }}م وحتى {{ frappe.utils.formatdate(doc.end_date, 'yyyy/MM/dd') }}م.</li><li>يتعهد الطرفان بصحة البيانات المدونة أعلاه.</li><li>يلتزم الطرفان بالمواعيد المحددة في تقديم الوجبات دون تأخير.</li><li>يحق للطرف الأول المطالبة بإلغاء التعهد والمطالبة بالمبالغ المتبقية في حالة زيادة الأعداد أو اختلاف البيانات المدونة، ولا يتم تعديل أي بند من القائمة أو جدول المواعيد إلا بموافقة كتابية.</li><li>يلتزم الطرف الثاني بتأمين عمالة بشهادات صحية للتوريد للفندق، ما لم ينص العقد على خلاف ذلك.</li><li>يجب على الفندق التدقيق والتأكد من صحة البيانات، وهي على مسؤولية الفندق في حالة عدم مطابقتها.</li><li>يحق للفندق رفض التعهد في حالة عدم صحة بيانات الأعداد أو الأيام أو الجنسية.</li><li>يلتزم الطرف الأول بتسليم الفندق صورة من الأوراق الرسمية المطلوبة، بما في ذلك السجل التجاري ورخصة البلدية والعقد الخاص بالتغذية متى طُلبت.</li></ol>
{% if doc.additional_terms %}<div><b>بنود إضافية:</b>{{ doc.additional_terms }}</div>{% endif %}{% if doc.service_notes %}<p><b>ملاحظات الخدمة:</b> {{ doc.service_notes }}</p>{% endif %}
<p class="closing">{{ s.closing_text }}</p>
<table class="sign"><tr>
<td><div class="sign-block"><b>الطرف الأول</b><div class="sign-name">{{ doc.company_name }}<br>{{ doc.authorized_signatory or s.signatory_name }}<br>{{ doc.signatory_title or s.signatory_title or '' }}</div>{% if signature %}<div class="image-box"><img class="sign-img" src="{{ frappe.utils.get_url(signature) }}"></div>{% endif %}</div></td>
{% if s.show_second_party_signature %}<td><div class="sign-block"><b>الطرف الثاني</b><div class="sign-name">{{ doc.second_party_name }}</div><div class="image-box">التوقيع: ____________________</div></div></td>{% else %}<td><div class="sign-block"><b>الختم</b>{% if stamp %}<div class="image-box"><img class="stamp-img" src="{{ frappe.utils.get_url(stamp) }}"></div>{% else %}<div class="image-box">____________________</div>{% endif %}</div></td>{% endif %}
</tr></table>
<div class="footer">{{ doc.company_phone }} &nbsp; | &nbsp; {{ doc.company_email }}{% if s.footer_text %} &nbsp; | &nbsp; {{ s.footer_text }}{% endif %}</div>
</div>
